private void xrTableCell22_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get values from fields
    decimal femaleBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleBalance") ?? 0);
    decimal maleBalance = Convert.ToDecimal(GetCurrentColumnValue("MaleBalance") ?? 0);

    // Calculate: (MaleBalance / FemaleBalance) * 100
    if (femaleBalance > 0) {
        decimal result = (maleBalance / femaleBalance) * 100;
        cell.Text = result.ToString("N2"); // 1 decimal place with %
        // Or without %: result.ToString("F1")
    } else {
        cell.Text = "0.00"; // or "0"
    }

    TotalfemaleBalanceReport += femaleBalance ;
    TotalmaleBalanceReport += maleBalance ;
    }

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      // Get values from fields
    decimal femaleBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleBalance") ?? 0);
    decimal maleBalance = Convert.ToDecimal(GetCurrentColumnValue("MaleBalance") ?? 0);

    TotalfemaleBalanceGroup += femaleBalance ;
    TotalmaleBalanceGroup += maleBalance ;

     // Get values for group accumulation
    decimal femalePlaced = Convert.ToDecimal(GetCurrentColumnValue("FemalePlaced") ?? 0);
    decimal femaleMort = Convert.ToDecimal(GetCurrentColumnValue("FemaleMort") ?? 0);

    // Accumulate for group totals
    totalFemalePlacedGroup += femalePlaced;
    totalFemaleMortGroup += femaleMort;

   decimal femaleCulls = Convert.ToDecimal(GetCurrentColumnValue("FemalCulls") ?? 0);

    // Accumulate for group totals
    totalFemalePlacedGroupCulls += femalePlaced;
    totalFemaleCullsGroup += femaleCulls;

    // Get values for group accumulation
    decimal malePlaced = Convert.ToDecimal(GetCurrentColumnValue("MalePlaced") ?? 0);
    decimal maleMort = Convert.ToDecimal(GetCurrentColumnValue("MaleMort") ?? 0);

    // Accumulate for group totals
    totalMalePlacedGroup += malePlaced;
    totalMaleMortGroup += maleMort;

        decimal maleCulls = Convert.ToDecimal(GetCurrentColumnValue("MaleCulls") ?? 0);

    // Accumulate for group totals
    totalMalePlacedGroupCulls += malePlaced;
    totalMaleCullsGroup += maleCulls;

    decimal cummFemaleMort = Convert.ToDecimal(GetCurrentColumnValue("CummFemaleMort") ?? 0);
    decimal cummFemalCulls = Convert.ToDecimal(GetCurrentColumnValue("CummFemalCulls") ?? 0);
    decimal cummFemaleMissex = Convert.ToDecimal(GetCurrentColumnValue("CummFemaleMissex") ?? 0);

    // Calculate @CummFemaleDepl
    decimal cummFemaleDeplGroup = cummFemaleMort + cummFemalCulls + cummFemaleMissex;

    // Calculate percentage: (@CummFemaleDepl / FemalePlaced) * 100
    if (femalePlaced > 0) {
        decimal result = (cummFemaleDeplGroup / femalePlaced) * 100;

        sumFemaleDeplPercentGroup += result;
        countFemaleDeplPercentGroup++;        
    }


    decimal cummMaleMort = Convert.ToDecimal(GetCurrentColumnValue("CummMaleMort") ?? 0);
    decimal cummMaleCulls = Convert.ToDecimal(GetCurrentColumnValue("CummMaleCulls") ?? 0);
    decimal cummMaleMissex = Convert.ToDecimal(GetCurrentColumnValue("CummMaleMissex") ?? 0);

    // Calculate @CummMaleDepl
    decimal cummMaleDeplGroup = cummMaleMort + cummMaleCulls + cummMaleMissex;

    // Calculate percentage: (@CummMaleDepl / MalePlaced) * 100
    if (malePlaced > 0) {
        decimal result = (cummMaleDeplGroup / malePlaced) * 100;

        // Store for AVERAGE calculation
        sumMaleDeplPercentGroup += result;
        countMaleDeplPercentGroup++;        
      }
}

